import React, { useState } from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent({
  city = "Tokyo",
  temperature = 28,
  condition = "Sunny",
  humidity = 45,
  windSpeed = 8,
  unit = "C",
  forecast = []
}: Props) {
  const [isHovered, setIsHovered] = useState(false);

  const displayUnit = unit ?? 'C';
  const safeForecast = forecast ?? [];

  return (
    <div
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      style={{
        transition: 'transform 200ms ease-in-out',
        transform: isHovered ? 'translateY(-2px)' : 'translateY(0)',
        width: '100%',
        maxWidth: '400px',
        margin: '0 auto'
      }}
    >
      <Card
        shadow={isHovered ? 'md' : 'sm'}
        radius="lg"
        padding={24}
        border
      >
        <Stack gap={24}>
          {/* Header Section */}
          <Stack direction="horizontal" justify="between" align="start">
            <Stack gap={4}>
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                {city ?? 'Unknown City'}
              </Heading>
              <Text variant="bodyLarge" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {condition ?? 'Clear'}
              </Text>
            </Stack>
            <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
              {temperature ?? 0}°{displayUnit}
            </Heading>
          </Stack>

          {/* Details Row */}
          <Stack direction="horizontal" gap={16} justify="start">
            <Stack gap={2}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Humidity
              </Text>
              <Text variant="bodySmall" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                {humidity ?? 0}%
              </Text>
            </Stack>
            <Divider orientation="vertical" margin={8} color="var(--ggui-color-outlineVariant, #e4e4e7)" />
            <Stack gap={2}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Wind Speed
              </Text>
              <Text variant="bodySmall" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed ?? 0} km/h
              </Text>
            </Stack>
          </Stack>

          {/* Forecast Section */}
          {safeForecast.length > 0 && (
            <Stack gap={16}>
              <Divider orientation="horizontal" margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />
              <div 
                style={{ 
                  display: 'flex', 
                  flexDirection: 'row', 
                  justifyContent: 'space-between',
                  overflowX: 'auto',
                  gap: 'var(--ggui-spacing-2, 8px)',
                  paddingBottom: 'var(--ggui-spacing-1, 4px)'
                }}
              >
                {safeForecast.map((item, index) => (
                  <Box 
                    key={`${item.day}-${index}`} 
                    padding={8} 
                    borderRadius={8}
                    background="var(--ggui-color-primary-50, #f0f9ff)"
                  >
                    <Stack gap={8} align="center">
                      <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {item.day ?? '---'}
                      </Text>
                      <Text size="xl">
                        <span role="img" aria-label="weather icon">
                          {item.icon ?? '☀️'}
                        </span>
                      </Text>
                      <Stack gap={0} align="center">
                        <Text 
                          variant="caption" 
                          weight="semibold" 
                          color="var(--ggui-color-error-600, #dc2626)"
                        >
                          {item.high ?? 0}°
                        </Text>
                        <Text 
                          variant="caption" 
                          color="var(--ggui-color-primary-600, #0284c7)"
                        >
                          {item.low ?? 0}°
                        </Text>
                      </Stack>
                    </Stack>
                  </Box>
                ))}
              </div>
            </Stack>
          )}
        </Stack>
      </Card>
    </div>
  );
}
